// Get the AI response
const aiResponse = $('Classify AI Agent').first().json.output;

function normalizeResponse(parsed) {
  return {
    classification: typeof parsed.classification === "string"
      ? parsed.classification
      : "other",

    confidence:
      typeof parsed.confidence === "number"
        ? Math.min(1, Math.max(0, parsed.confidence))
        : 0.0,

    entities: {
      ingredient: parsed.entities?.ingredient ?? null,
      recipe: parsed.entities?.recipe ?? null,
      ingredients: Array.isArray(parsed.entities?.ingredients)
        ? parsed.entities.ingredients
        : null,

      substitutes: Array.isArray(parsed.entities?.substitutes)
        ? parsed.entities.substitutes
        : null,

      required_ingredients: Array.isArray(parsed.entities?.required_ingredients)
        ? parsed.entities.required_ingredients
        : null,

      replacement: parsed.entities?.replacement ?? null,

      original_ingredients: Array.isArray(parsed.entities?.original_ingredients)
        ? parsed.entities.original_ingredients
        : null,

      recipe_context: parsed.entities?.recipe_context ?? null,
      attributes: parsed.entities?.attributes ?? null,
      natural_description: parsed.entities?.natural_description ?? null,
      recipe_title: parsed.entities?.recipe_title ?? null,

      include_reasoning:
        typeof parsed.entities?.include_reasoning === "boolean"
          ? parsed.entities.include_reasoning
          : false,

      max_results:
        typeof parsed.entities?.max_results === "number"
          ? parsed.entities.max_results
          : 5
    }
  };
}

try {
  const parsedResponse = JSON.parse(aiResponse);

  if (!parsedResponse.entities) {
    parsedResponse.entities = {};
  }

  const result = normalizeResponse(parsedResponse);

  return { json: result };

} catch (error) {
  return {
    json: {
      classification: "other",
      confidence: 0.0,
      entities: {
        ingredient: null,
        recipe: null,
        ingredients: null,
        substitutes: null,
        required_ingredients: null,
        replacement: null,
        original_ingredients: null,
        recipe_context: null,
        attributes: null,
        natural_description: null,
        recipe_title: null,
        include_reasoning: false,
        max_results: 5
      },
      error: "Failed to parse AI response"
    }
  };
}
